############
# COMPILE #
############

set R_HOME=C:\progra~1\R\rw1051

path;
PATH=%SystemRoot%\system32;%SystemRoot%;C:\PROGRA~1\R\rw1051\tools;C:\PROGRA
~1\R\rw1051\MinGW\bin
